(1, 'android', '1.0.0', 1, 'https://home.mbed.org.cn:9090/static/downloads/material-management-1.0.0.apk', false, '初始版本', '首次发布材料管理系统移动端\n- 完整的物资管理功能\n- 预约管理功能\n- 入库/出库管理\n- 数据统计与报表', '2026-02-11 04:23:56', '2026-02-11 04:23:56', '2026-02-11 04:23:56'),
(3, 'android', '1.0.1', 2, 'https://home.mbed.org.cn:9090/static/downloads/material-management-1.0.0.apk', false, '优化功能，修复已知问题', '更新内容：\n- 同步时间段配置与 Web 端\n- 修复自动更新检测问题\n- 优化用户体验', '2026-02-11 05:57:41', '2026-02-11 05:57:41', '2026-02-11 05:57:41'),
(4, 'android', '1.0.2', 0, 'https://home.mbed.org.cn:9090/mobile-updates/latest.apk', false, '发现新版本 1.0.2，立即更新', '版本 1.0.2 更新：\n- 施工预约管理功能优化\n- 头像上传裁剪功能修复\n- 多选作业人员支持\n- 提交按钮显示修复\n- UI优化和bug修复', '2026-02-11 14:16:01', '2026-02-11 14:16:01', '2026-02-11 14:16:01'),
(18, 'android', '1.0.16', 0, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.16.apk', false, '修复头像显示问题', '- 修复头像不显示的问题\n- 添加默认头像（当用户没有头像时显示）\n- 创建 avatars 目录\n- 优化 getAssetUrl 函数逻辑', '2026-02-15 14:35:16', '2026-02-15 14:35:16', '2026-02-15 14:35:16'),
(19, 'android', '1.0.25', 0, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.25.apk', false, '发现新版本，请更新以获得更好的体验', '- 修复审批历史显示问题 - 过滤掉start和end特殊节点\n- 优化审批节点显示逻辑', '2026-02-18 08:37:06', '2026-02-18 08:37:06', '2026-02-18 08:37:06'),
(5, 'android', '1.0.3', 0, 'http://home.mbed.org.cn:9090/api/app/download-apk?platform=android&version=1.0.3', false, '发现新版本 1.0.3，立即更新', '版本 1.0.3 更新：\n- 添加手动检查更新功能\n- 优化头像裁剪组件\n- 修复作业人员提交问题\n- 修复提交按钮显示问题\n- UI优化和性能改进', '2026-02-11 16:19:22', '2026-02-11 16:19:22', '2026-02-11 16:19:22'),
(6, 'android', '1.0.4', 0, 'https://home.mbed.org.cn:9090/mobile-updates/latest.apk', false, '发现新版本 1.0.4，刷新页面即可更新', '版本 1.0.4 更新：\n- 功能优化\n- bug修复\n- 用户体验改进', '2026-02-12 11:02:57', '2026-02-12 11:02:57', '2026-02-12 11:02:57'),
(7, 'android', '1.0.5', 0, 'https://home.mbed.org.cn:9090/mobile-updates/material-management-1.0.5.apk', false, '发现新版本 1.0.5，立即更新', '版本 1.0.5 更新：\n- 功能优化\n- bug修复\n- 用户体验改进', '2026-02-12 11:04:39', '2026-02-12 11:04:39', '2026-02-12 11:04:39'),
(8, 'android', '1.0.6', 0, 'https://home.mbed.org.cn:9090/mobile-updates/material-management-1.0.6.apk', false, '发现新版本 1.0.6，请立即更新', '版本 1.0.6 更新：\n- 修复头像显示问题\n- 修复所有提示框样式（白底白字问题）\n- 优化图片加载性能\n- 改进用户体验', '2026-02-12 14:14:41', '2026-02-12 14:14:41', '2026-02-12 14:14:41'),
(9, 'android', '1.0.7', 0, 'https://home.mbed.org.cn:9090/mobile-updates/material-management-1.0.7.apk', false, '发现新版本 1.0.7，请立即更新', '版本 1.0.7 更新：\n- 优化预约单创建流程\n- 只能选择明天之后的日期\n- 普通预约受人员可用性限制\n- 加急预约不受限制\n- 显示时间段繁忙程度', '2026-02-13 13:24:05', '2026-02-13 13:24:05', '2026-02-13 13:24:05'),
(10, 'android', '1.0.8', 0, 'https://home.mbed.org.cn:9090/mobile-updates/material-management-1.0.8.apk', false, '发现新版本 1.0.8，请立即更新', '版本 1.0.8 更新：\n- 测试版本更新功能\n- 优化预约单创建流程', '2026-02-13 13:34:49', '2026-02-13 13:34:49', '2026-02-13 13:34:49'),
(11, 'android', '1.0.9', 0, 'https://home.mbed.org.cn:9090/mobile-updates/material-management-1.0.9.apk', false, '发现新版本 1.0.9，立即更新', '版本 1.0.9 更新：\\n- 修复关于页面版本显示\\n- 添加发布日期显示\\n- 优化用户体验', '2026-02-13 13:51:40', '2026-02-13 13:51:40', '2026-02-13 13:51:40'),
(12, 'android', '1.0.10', 0, 'https://home.mbed.org.cn:9090/mobile-updates/material-management-1.0.10.apk', false, '发现新版本 1.0.10，立即更新', '版本 1.0.10 更新：\\n- 修复人员头像显示问题\\n- 优化版本检测\\n- 简化下载流程', '2026-02-13 15:11:39', '2026-02-13 15:11:39', '2026-02-13 15:11:39'),
(13, 'android', '1.0.11', 0, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.11.apk', false, '添加预约单审批功能', '- 新增预约单审批功能（审批通过/拒绝）- 待审批状态可进行审批操作', '2026-02-13 17:33:02', '2026-02-13 17:33:02', '2026-02-13 17:33:02'),
(14, 'android', '1.0.12', 0, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.12.apk', false, '添加预约单审批功能（权限控制）', '- 新增审批通过/拒绝按钮\\n- 根据审批权限控制显示（不能审批自己的预约单）\\n- 修复 Web 端 MIME type 错误', '2026-02-14 08:40:58', '2026-02-14 08:40:58', '2026-02-14 08:40:58'),
(15, 'android', '1.0.13', 0, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.13.apk', false, '根据角色动态显示菜单，首页增加预约单快捷入口', '- 底部菜单根据角色不同显示不同菜单项\n- 管理员：首页、预约管理、入库管理、我的\n- 作业人员：首页、我的\n- 普通用户：首页、预约、我的', '2026-02-14 11:34:05', '2026-02-14 11:34:05', '2026-02-14 11:34:05'),
(16, 'android', '1.0.14', 0, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.14.apk', false, '优化自动更新功能和服务器重启', '- 优化自动更新检查逻辑\n- 添加应用从后台恢复时检查更新\n- 修复跳过版本的判断逻辑\n- 添加详细的更新日志输出', '2026-02-15 14:26:26', '2026-02-15 14:26:26', '2026-02-15 14:26:26'),
(20, 'android', '1.0.26', 0, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.26.apk', false, '修复审批历史显示问题', '- 修复 pm_approve 显示为中文项目经理审批\n- 过滤掉 start 和 end 特殊节点\n- 优化审批节点显示逻辑', '2026-02-18 08:46:27', '2026-02-18 08:46:27', '2026-02-18 08:46:27'),
(22, 'android', '1.0.27', 27, NULL, false, '优化作业类型显示和用户体验', '1. 预约单详情中作业类型现在显示中文标签（如：一般作业、动火作业等） 2. 优化了多项用户界面细节 3. 修复了已知问题并提升性能', '2026-03-02 06:40:36', '2026-03-02 06:40:36', '2026-03-02 06:40:36'),
(23, 'android', '1.0.28', 28, NULL, false, '实现基于权限的菜单和功能显示', '1. 菜单和快捷功能现在根据用户权限动态显示 2. 不同权限的用户看到的功能不同 3. 支持预约、物资计划、入库、出库、日志、进度等模块 4. 优化用户体验和权限管理', '2026-03-02 08:07:47', '2026-03-02 08:07:47', '2026-03-02 08:07:47'),
(24, 'android', '1.0.29', 0, NULL, false, '新增物资计划创建功能和权限控制优化', '1. 新增移动端物资计划创建功能 2. 优化作业人员选择 3. 完善权限控制系统 4. 修复若干已知问题', '2026-03-19 07:25:43', '2026-03-19 07:25:43', '2026-03-19 07:25:43'),
(25, 'android', '1.0.30', 0, NULL, false, '预约管理默认显示日历视图', '1. 预约管理默认显示日历视图 2. 优化用户体验 3. 修复若干已知问题', '2026-03-19 07:31:47', '2026-03-19 07:31:47', '2026-03-19 07:31:47'),
(26, 'android', '1.0.31', 0, NULL, false, '日历长按新建预约功能', '1. 日历支持长按新建预约 2. 优化用户体验 3. 修复若干已知问题', '2026-03-19 07:59:17', '2026-03-19 07:59:17', '2026-03-19 07:59:17'),
(27, 'android', '1.0.32', 0, NULL, false, '日历页面添加新建预约按钮', '1. 日历页面添加新建预约按钮 2. 修复若干已知问题', '2026-03-19 08:06:57', '2026-03-19 08:06:57', '2026-03-19 08:06:57'),
(28, 'android', '1.0.33', 0, NULL, false, '修复项目选择为空问题', '1. 项目选择现在显示所有项目 2. 修复若干已知问题', '2026-03-19 08:16:45', '2026-03-19 08:16:45', '2026-03-19 08:16:45'),
(29, 'android', '1.0.36', 36, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.36.apk', false, '发现新版本 1.0.36，优化项目选择器和导航体验', '版本 1.0.36 更新：\n- 修复项目选择器不显示的问题\n- 优化首页图标颜色\n- 移除系统公告栏\n- 修复新建页面点击首页无效的问题\n- 修复预约管理退出需要后退两步的问题\n- 优化作业人员名字显示（最多4个）', '2026-03-19 13:29:20', '2026-03-19 13:29:20', '2026-03-19 13:29:20'),
(30, 'android', '1.0.37', 37, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.37.apk', false, '版本更新优化', '版本 1.0.37 更新：\\n- 数据库迁移更新\\n- 权限字段优化', '2026-03-22 03:50:16', '2026-03-22 03:50:16', '2026-03-22 03:50:16'),
(31, 'android', '1.0.38', 38, 'https://home.mbed.org.cn:9090/mobile-updates/android/material-management-1.0.38.apk', false, '修复头像显示问题', '版本 1.0.38 更新：\\n- 修复 Base64 头像无法显示的问题', '2026-03-22 04:05:31', '2026-03-22 04:05:31', '2026-03-22 04:05:31'),
